import { describe, expect, it } from 'vitest'

import { EncryptedFields } from './encryption'

// Fixtures decrypt real Django-written ciphertext; `trickyKey`'s base64 contains
// `+`/`/`, the case where standard vs urlsafe base64 derivation diverges.
// Generated by posthog/helpers/encrypted_fields.py's derivation via Python Fernet.
const FIXTURES = {
    safeKey: 'a_very_secret_salt_key_32_bytes!',
    trickyKey: '~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~?',
    safeToken:
        'gAAAAABqREGn3YEj5EgsqDzxxfmwhZKhDHGqjcr0bdhaeEz9qX9zywiVDvcFGyQQticdRN82T1nlrUgfaa1KZ7Wi-GI0srFJQhhqjCCdWqFFs_cOu5WazZw=',
    trickyToken:
        'gAAAAABqREGnwU9VnjMcO9wcSFIJlWyyEJDnh2aqUSTbgOCWb7mBdPx6aH1KrkErqsBTxXCgUbYdulRXFYl0QYwEVaYWb2JUFHWXFrOS0rAo5FA5XRxXnXQ=',
    leaf3600: 'gAAAAABqREGnsLgiWzBjhTwlT9zdQsgJJPcVZI5CNtHQ2Csxjp7iSx1pGxNbRYg0eFMsNip4BDgaXKgOsJmjx7Zqkj08zN8VQQ==',
} as const

describe('Django ↔ TS encryption interop', () => {
    it('decrypts a Django-written token for a base64-safe salt key', () => {
        expect(new EncryptedFields(FIXTURES.safeKey).decrypt(FIXTURES.safeToken)).toBe('hello-django-secret')
    })

    it('decrypts a Django-written token for a key whose base64 contains +// (urlsafe regression)', () => {
        expect(new EncryptedFields(FIXTURES.trickyKey).decrypt(FIXTURES.trickyToken)).toBe('hello-django-secret')
    })

    it('decrypts a per-leaf JSON-field value (str()-encoded scalar) as Django writes it', () => {
        // Django encodes each scalar leaf as encrypt(str(value)); "3600" comes back as a string.
        expect(new EncryptedFields(FIXTURES.safeKey).decryptJsonFieldValue(FIXTURES.leaf3600)).toBe('3600')
    })
})
